1	// COR24 APL Interpreter -- Parser
2	// Right-to-left recursive descent with vector literal stranding.
3	// APL: all operators equal precedence, right-associative.
4	// 2 + 3 * 4  ->  2 + (3 * 4)  ->  14
5	// 1 2 3      ->  3-element vector (adjacent numbers strand)
6	
7	#pragma once
8	
9	// AST node types
10	#define NODE_NUM    0   // integer literal (val = value)
11	#define NODE_BINOP  1   // binary op (val = operator tok type)
12	#define NODE_NEG    2   // monadic negate (right = operand)
13	#define NODE_IDENT  3   // variable reference (val = symbol index)
14	#define NODE_ASSIGN 4   // assignment (val = symbol index, right = expr)
15	#define NODE_VEC    5   // vector literal (val = heap array index)
16	#define NODE_MONAD  6   // monadic primitive (val = RES_xxx, right = operand)
17	#define NODE_DYAD   7   // dyadic primitive (val = RES_xxx, left/right = args)
18	#define NODE_REDUCE 8   // reduce operator (val = op tok type, right = operand)
19	#define NODE_QOUT   9   // quad output (right = expr to print)
20	#define NODE_QLED  10   // qled read (no children)
21	#define NODE_QLED_ASSIGN 11  // qled <- expr (right = expr)
22	#define NODE_QSW   12   // qsw read (no children, read-only)
23	
24	#define AST_MAX 64
25	
26	// AST storage (parallel arrays)
27	int node_type[AST_MAX];
28	int node_val[AST_MAX];
29	int node_left[AST_MAX];
30	int node_right[AST_MAX];
31	int node_count;
32	
33	// Parser state
34	int parse_pos;
35	int parse_err;
36	char *parse_line;   // source line for identifier lookup
37	
38	// Allocate a new AST node
39	int ast_new() {
40	    if (node_count >= AST_MAX) {
41	        parse_err = 1;
42	        return 0;
43	    }
44	    int n = node_count;
45	    node_count++;
46	    node_left[n] = -1;
47	    node_right[n] = -1;
48	    return n;
49	}
50	
51	int ast_num(int val) {
52	    int n = ast_new();
53	    node_type[n] = NODE_NUM;
54	    node_val[n] = val;
55	    return n;
56	}
57	
58	int ast_binop(int op, int left, int right) {
59	    int n = ast_new();
60	    node_type[n] = NODE_BINOP;
61	    node_val[n] = op;
62	    node_left[n] = left;
63	    node_right[n] = right;
64	    return n;
65	}
66	
67	int ast_neg(int operand) {
68	    int n = ast_new();
69	    node_type[n] = NODE_NEG;
70	    node_right[n] = operand;
71	    return n;
72	}
73	
74	int ast_ident(int sym_idx) {
75	    int n = ast_new();
76	    node_type[n] = NODE_IDENT;
77	    node_val[n] = sym_idx;
78	    return n;
79	}
80	
81	int ast_assign(int sym_idx, int expr) {
82	    int n = ast_new();
83	    node_type[n] = NODE_ASSIGN;
84	    node_val[n] = sym_idx;
85	    node_right[n] = expr;
86	    return n;
87	}
88	
89	int ast_vec(int heap_idx) {
90	    int n = ast_new();
91	    node_type[n] = NODE_VEC;
92	    node_val[n] = heap_idx;
93	    return n;
94	}
95	
96	int ast_monad(int res_id, int operand) {
97	    int n = ast_new();
98	    node_type[n] = NODE_MONAD;
99	    node_val[n] = res_id;
100	    node_right[n] = operand;
101	    return n;
102	}
103	
104	int ast_dyad(int res_id, int left, int right) {
105	    int n = ast_new();
106	    node_type[n] = NODE_DYAD;
107	    node_val[n] = res_id;
108	    node_left[n] = left;
109	    node_right[n] = right;
110	    return n;
