148	            if (count < 0) { eval_err = 1; return -1; }
149	            int r = arr_vector(count);
150	            if (r < 0) { eval_err = 5; return -1; }
151	            int i = 0;
152	            while (i < count) {
153	                arr_set(r, i, i);
154	                i++;
155	            }
156	            return r;
157	        }
