162	            if (rk == 0) {
163	                // Scalar: shape is empty vector
164	                int r = arr_vector(0);
165	                if (r < 0) { eval_err = 5; return -1; }
166	                return r;
167	            }
168	            if (rk == 1) {
169	                // Vector: shape is 1-element vector with length
170	                int r = arr_scalar(arr_dim0(v));
171	                if (r < 0) { eval_err = 5; return -1; }
172	                return r;
173	            }
174	            if (rk == 2) {
175	                // Matrix: shape is 2-element vector (rows cols)
176	                int r = arr_vector(2);
177	                if (r < 0) { eval_err = 5; return -1; }
178	                arr_set(r, 0, arr_dim0(v));
179	                arr_set(r, 1, arr_dim1(v));
