                int lsz = arr_size(lv);
                if (lsz == 1) {
                    new_rank = 1;
                    d0 = arr_get(lv, 0);
                    d1 = 0;
                    if (d0 < 0) { eval_err = 1; return -1; }
                } else if (lsz == 2) {
                    new_rank = 2;
                    d0 = arr_get(lv, 0);
                    d1 = arr_get(lv, 1);
                    if (d0 < 0 || d1 < 0) { eval_err = 1; return -1; }
                } else {
                    // Only rank 1 and 2 supported
                    eval_err = 4;
                    return -1;
                }
            } else {
                eval_err = 4;
                return -1;
            }

            int r = arr_new(new_rank, d0, d1);
            if (r < 0) { eval_err = 5; return -1; }

            int total = arr_size(r);
            int src_sz = arr_size(rv);
            if (src_sz == 0) { eval_err = 3; return -1; }

            int i = 0;
            while (i < total) {
                arr_set(r, i, arr_get(rv, i % src_sz));
                i++;
            }
            return r;
        }

        if (res_id == RES_TAKE) {
            // N take A: take first N elements/rows (negative N = from end)
            if (arr_rank(lv) != 0) { eval_err = 4; return -1; }
            int count = arr_get(lv, 0);
            int rrk = arr_rank(rv);

            if (rrk <= 1) {
                int sz = arr_size(rv);
                int abs_n = count;
                if (abs_n < 0) abs_n = 0 - abs_n;
                if (abs_n > sz) { eval_err = 3; return -1; }

                int r = arr_vector(abs_n);
                if (r < 0) { eval_err = 5; return -1; }
                int start = 0;
                if (count < 0) start = sz - abs_n;
                int i = 0;
                while (i < abs_n) {
                    arr_set(r, i, arr_get(rv, start + i));
                    i++;
                }
                return r;
            }

            if (rrk == 2) {
                int rows = arr_dim0(rv);
                int cols = arr_dim1(rv);
                int abs_n = count;
                if (abs_n < 0) abs_n = 0 - abs_n;
                if (abs_n > rows) { eval_err = 3; return -1; }

                int r = arr_new(2, abs_n, cols);
                if (r < 0) { eval_err = 5; return -1; }
                int start_row = 0;
                if (count < 0) start_row = rows - abs_n;
                int total = abs_n * cols;
                int i = 0;
                while (i < total) {
                    arr_set(r, i, arr_get(rv, start_row * cols + i));
                    i++;
                }
                return r;
            }

            eval_err = 4;
            return -1;
        }

        if (res_id == RES_DROP) {
            // N drop A: drop first N elements/rows (negative N = from end)
            if (arr_rank(lv) != 0) { eval_err = 4; return -1; }
            int count = arr_get(lv, 0);
            int rrk = arr_rank(rv);

            if (rrk <= 1) {
                int sz = arr_size(rv);
                int abs_n = count;
                if (abs_n < 0) abs_n = 0 - abs_n;
                if (abs_n > sz) abs_n = sz;

                int new_sz = sz - abs_n;
                int r = arr_vector(new_sz);
                if (r < 0) { eval_err = 5; return -1; }
                int start = abs_n;
                if (count < 0) start = 0;
                int i = 0;
                while (i < new_sz) {
                    arr_set(r, i, arr_get(rv, start + i));
                    i++;
                }
                return r;
            }

            if (rrk == 2) {
                int rows = arr_dim0(rv);
                int cols = arr_dim1(rv);
                int abs_n = count;
                if (abs_n < 0) abs_n = 0 - abs_n;
                if (abs_n > rows) abs_n = rows;

                int new_rows = rows - abs_n;
                int r = arr_new(2, new_rows, cols);
                if (r < 0) { eval_err = 5; return -1; }
                int start_row = abs_n;
                if (count < 0) start_row = 0;
                int total = new_rows * cols;
                int i = 0;
                while (i < total) {
                    arr_set(r, i, arr_get(rv, start_row * cols + i));
                    i++;
                }
                return r;
            }

            eval_err = 4;
            return -1;
        }

        if (res_id == RES_CAT) {
            // Dyadic cat: catenate two arrays
            int lrk = arr_rank(lv);
            int rrk = arr_rank(rv);
            int lsz = arr_size(lv);
            int rsz = arr_size(rv);
            int total = lsz + rsz;
            int r = arr_vector(total);
            if (r < 0) { eval_err = 5; return -1; }
            int i = 0;
            while (i < lsz) {
                arr_set(r, i, arr_get(lv, i));
                i++;
            }
            i = 0;
            while (i < rsz) {
                arr_set(r, lsz + i, arr_get(rv, i));
                i++;
            }
            return r;
        }

        // Unknown dyadic function
        eval_err = 1;
        return -1;
    }

    if (ty == NODE_BINOP) {
        int lv = eval(node_left[n]);
        if (eval_err) return -1;
        int rv = eval(node_right[n]);
        if (eval_err) return -1;

        int lrk = arr_rank(lv);
        int rrk = arr_rank(rv);
        int op = node_val[n];

        // Scalar op scalar
        if (lrk == 0 && rrk == 0) {
            int result = eval_binop_scalar(op, arr_get(lv, 0), arr_get(rv, 0));
            if (eval_err) return -1;
            int r = arr_scalar(result);
            if (r < 0) { eval_err = 5; return -1; }
            return r;
        }

        // Vector op vector: must match length
        if (lrk == 1 && rrk == 1) {
            int lsz = arr_size(lv);
            int rsz = arr_size(rv);
            if (lsz != rsz) { eval_err = 3; return -1; }
            int r = arr_vector(lsz);
            if (r < 0) { eval_err = 5; return -1; }
            int i = 0;
            while (i < lsz) {
                int val = eval_binop_scalar(op, arr_get(lv, i), arr_get(rv, i));
                if (eval_err) return -1;
                arr_set(r, i, val);
                i++;
            }
            return r;
        }

        // Scalar op vector
        if (lrk == 0 && rrk == 1) {
            int la = arr_get(lv, 0);
            int rsz = arr_size(rv);
            int r = arr_vector(rsz);
            if (r < 0) { eval_err = 5; return -1; }
            int i = 0;
            while (i < rsz) {
                int val = eval_binop_scalar(op, la, arr_get(rv, i));
                if (eval_err) return -1;
                arr_set(r, i, val);
                i++;
            }
            return r;
        }

        // Vector op scalar
        if (lrk == 1 && rrk == 0) {
            int ra = arr_get(rv, 0);
            int lsz = arr_size(lv);
            int r = arr_vector(lsz);
            if (r < 0) { eval_err = 5; return -1; }
            int i = 0;
            while (i < lsz) {
                int val = eval_binop_scalar(op, arr_get(lv, i), ra);
                if (eval_err) return -1;
                arr_set(r, i, val);
                i++;
            }
            return r;
        }

        // Matrix op matrix: must match shape
        if (lrk == 2 && rrk == 2) {
            if (arr_dim0(lv) != arr_dim0(rv) || arr_dim1(lv) != arr_dim1(rv)) {
                eval_err = 3; return -1;
            }
            int d0 = arr_dim0(lv);
            int d1 = arr_dim1(lv);
            int r = arr_new(2, d0, d1);
            if (r < 0) { eval_err = 5; return -1; }
            int sz = d0 * d1;
            int i = 0;
            while (i < sz) {
                int val = eval_binop_scalar(op, arr_get(lv, i), arr_get(rv, i));
                if (eval_err) return -1;
                arr_set(r, i, val);
                i++;
            }
            return r;
        }

        // Scalar op matrix
        if (lrk == 0 && rrk == 2) {
            int la = arr_get(lv, 0);
            int d0 = arr_dim0(rv);
            int d1 = arr_dim1(rv);
            int r = arr_new(2, d0, d1);
            if (r < 0) { eval_err = 5; return -1; }
            int sz = d0 * d1;
            int i = 0;
            while (i < sz) {
                int val = eval_binop_scalar(op, la, arr_get(rv, i));
                if (eval_err) return -1;
                arr_set(r, i, val);
                i++;
            }
            return r;
        }

        // Matrix op scalar
        if (lrk == 2 && rrk == 0) {
            int ra = arr_get(rv, 0);
            int d0 = arr_dim0(lv);
            int d1 = arr_dim1(lv);
            int r = arr_new(2, d0, d1);
            if (r < 0) { eval_err = 5; return -1; }
            int sz = d0 * d1;
            int i = 0;
            while (i < sz) {
                int val = eval_binop_scalar(op, arr_get(lv, i), ra);
                if (eval_err) return -1;
                arr_set(r, i, val);
                i++;
            }
            return r;
        }

        // Unsupported rank combination
        eval_err = 4;
        return -1;
    }

    eval_err = 1;
    return -1;
}

// COR24 APL Interpreter -- main entry point
// Phase 6: shared variable I/O (qled quad LED)

#include <stdio.h>
#include "io.h"
#include "num.h"
#include "arr.h"
#include "tok.h"
#include "sym.h"
#include "parse.h"
#include "eval.h"

int main() {
    char line[IO_LINE_MAX];

    arr_reset();
    puts("COR24 APL v0.1");

    while (1) {
        io_print("      ");
        int n = io_getline(line, IO_LINE_MAX);
        if (n == 0) {
            // Empty line -- just re-prompt
        } else if (line[0] == 41) {
            // System command: starts with ')'
            if (str_match(line, 1, "CLEAR") == 5 && (line[6] == 0 || line[6] == 32)) {
                arr_reset();
                sym_reset();
                io_print("  CLEAR WS");
                putchar(10);
            } else if (str_match(line, 1, "VARS") == 4 && (line[5] == 0 || line[5] == 32)) {
                int i = 0;
                int any = 0;
                while (i < sym_count) {
                    if (sym_set_flag[i]) {
                        if (any) io_print("  ");
                        int off = sym_name_off[i];
                        while (sym_name_buf[off]) {
                            putchar(sym_name_buf[off]);
                            off++;
                        }
                        any = 1;
                    }
                    i++;
                }
                if (any) putchar(10);
            } else if (str_match(line, 1, "OFF") == 3 && (line[4] == 0 || line[4] == 32)) {
                return 0;
            } else {
                io_print("  SYNTAX ERROR");
                putchar(10);
            }
        } else {
            int ntok = tokenize(line);
            if (ntok < 0) {
                io_print("  SYNTAX ERROR");
                putchar(10);
            } else {
                // Save heap position for temporary reclamation
                int heap_save = heap_top;

                int root = parse(line);
                if (root < 0) {
                    heap_top = heap_save;
                    io_print("  SYNTAX ERROR");
                    putchar(10);
                } else {
                    eval_err = 0;
                    int result = eval(root);
                    if (eval_err == 2) {
                        heap_top = heap_save;
                        io_print("  VALUE ERROR");
                        putchar(10);
                    } else if (eval_err == 3) {
                        heap_top = heap_save;
                        io_print("  LENGTH ERROR");
                        putchar(10);
                    } else if (eval_err == 4) {
                        heap_top = heap_save;
                        io_print("  RANK ERROR");
                        putchar(10);
                    } else if (eval_err == 5) {
                        heap_top = heap_save;
                        io_print("  WS FULL");
                        putchar(10);
                    } else if (eval_err) {
                        heap_top = heap_save;
                        io_print("  DOMAIN ERROR");
                        putchar(10);
                    } else if (node_type[root] == NODE_ASSIGN) {
                        // Assignment: no output (APL convention)
                        // Don't restore heap -- variable value persists
                    } else if (node_type[root] == NODE_QLED_ASSIGN) {
                        // Quad LED assignment: no output
                        heap_top = heap_save;
                    } else {
                        // Print result based on rank
                        int rank = arr_rank(result);
                        if (rank == 0) {
                            io_print("  ");
                            print_int(arr_get(result, 0));
                            putchar(10);
                        } else if (rank == 1) {
                            int sz = arr_dim0(result);
                            // Find max width across all elements
                            int maxw = 1;
                            int j = 0;
                            while (j < sz) {
                                int w = num_width(arr_get(result, j));
                                if (w > maxw) maxw = w;
                                j++;
                            }
                            // Print each element right-justified
                            j = 0;
                            while (j < sz) {
                                if (j == 0) putchar(32);
                                print_int_rj(arr_get(result, j), maxw);
                                if (j + 1 < sz) putchar(32);
                                j++;
                            }
                            putchar(10);
                        } else if (rank == 2) {
                            int rows = arr_dim0(result);
                            int cols = arr_dim1(result);
                            int sz = rows * cols;
                            // Find max width across all elements
                            int maxw = 1;
                            int j = 0;
                            while (j < sz) {
                                int w = num_width(arr_get(result, j));
                                if (w > maxw) maxw = w;
                                j++;
                            }
                            // Print each row on its own line
                            int r = 0;
                            while (r < rows) {
                                int c = 0;
                                while (c < cols) {
                                    if (c == 0) putchar(32);
                                    print_int_rj(arr_get(result, r * cols + c), maxw);
                                    if (c + 1 < cols) putchar(32);
                                    c++;
                                }
                                putchar(10);
                                r++;
                            }
                        }
                        // Reclaim temporaries
                        heap_top = heap_save;
                    }
                }
            }
        }
    }
    return 0;
}
